const input = $input.first().json;
const lead = $('Extract Lead Data').first().json;

let replyBody = lead.replyText || lead.replyPreview || 'N/A';
const separators = [
  /\n_{10,}/, /\n-{10,}/, /\nDe\s*:.*<.*>/, /\nFrom\s*:.*<.*>/,
  /\nEnvoy[e\u00e9]\s*:/, /\nSent\s*:/, /\nLe \d{1,2}.*a [e\u00e9]crit\s*:/,
  /\nOn \w{3},.*wrote\s*:/, /\nVous n'obtenez pas souvent/
];
for (const sep of separators) {
  const match = replyBody.search(sep);
  if (match > 0) { replyBody = replyBody.substring(0, match).trim(); break; }
}

const lemlistUrl = `https://app.lemlist.com/teams/${lead.teamId}/inbox/list/myConversations/contacts/${lead.contactId}`;

const actionPayload = {
  leadEmail: lead.leadEmail,
  contactId: lead.contactId,
  leadId: lead.leadId,
  teamId: lead.teamId,
  sendUserId: lead.sendUserId,
  senderEmail: lead.senderEmail,
  sendUserMailboxId: lead.sendUserMailboxId,
  subject: lead.subject,
  category: input.output.category,
  draft: input.output.draft
};

// ========== CLIENT CONFIG ==========
// \u2b07\ufe0f Change this channel ID for each client
const SLACK_CHANNEL = $('Config').first().json.slackChannelId; //
// ===================================

const blocks = [
  {
    "type": "section",
    "text": { "type": "mrkdwn", "text": "\ud83d\udce9 *You received a new answer!*" }
  },
  {
    "type": "section",
    "fields": [
      { "type": "mrkdwn", "text": `*Category:* \`${input.output.category}\`` },
      { "type": "mrkdwn", "text": `*Detected tone:* \`${input.output.detected_tone}\`` },
      { "type": "mrkdwn", "text": `*Lead:* ${lead.leadEmail}` },
      { "type": "mrkdwn", "text": `*Campaign:* ${lead.campaignName}` }
    ]
  },
  { "type": "divider" },
  {
    "type": "section",
    "text": { "type": "mrkdwn", "text": `\ud83d\udcac *Lead's answer :*\n>${replyBody.replace(/\n/g, '\n>')}` }
  },
  { "type": "divider" },
  {
    "type": "section",
    "text": { "type": "mrkdwn", "text": `\u2709\ufe0f *AI answer draft :*\n\`\`\`${input.output.draft}\`\`\`` }
  },
  {
    "type": "section",
    "text": { "type": "mrkdwn", "text": `\ud83d\udc49 <${lemlistUrl}|Open in the Lemlist Inbox>` }
  },
  {
    "type": "actions",
    "elements": [
      {
        "type": "button",
        "text": { "type": "plain_text", "text": "Manage it myself", "emoji": true },
        "action_id": "lemlist_disapprove",
        "url": lemlistUrl,
        "value": JSON.stringify({ leadEmail: lead.leadEmail, contactId: lead.contactId, teamId: lead.teamId, category: input.output.category })
      },
      {
        "type": "button",
        "text": { "type": "plain_text", "text": "Modify and send", "emoji": true },
        "action_id": "lemlist_edit",
        "value": JSON.stringify(actionPayload)
      },
      {
        "type": "button",
        "text": { "type": "plain_text", "text": "Send the draft", "emoji": true },
        "style": "primary",
        "action_id": "lemlist_approve",
        "value": JSON.stringify(actionPayload)
      }
    ]
  }
];

return [{
  json: {
    apiBody: {
      channel: SLACK_CHANNEL,
      text: `New answer from ${lead.leadEmail} (${input.output.category})`,
      blocks: blocks
    }
  }
}];

const raw = $input.first().json;
let payload;
if (raw.body && raw.body.payload) {
  payload = JSON.parse(raw.body.payload);
} else if (raw.payload) {
  payload = JSON.parse(raw.payload);
} else {
  payload = raw;
}

// Determine interaction type
const interactionType = payload.type; // 'block_actions' or 'view_submission'

if (interactionType === 'view_submission') {
  // Modal form submitted — extract edited message
  const values = payload.view.state.values;
  const editedDraft = values['edit-draft-block']['edit-draft-input'].value;

  // Recover metadata passed through private_metadata
  let meta = {};
  try {
    meta = JSON.parse(payload.view.private_metadata);
  } catch (e) { meta = {}; }

  return [{
    json: {
      actionType: 'modal_submit',
      editedDraft: editedDraft,
      triggerId: null,
      channel: meta.channel || '',
      messageTs: meta.messageTs || '',
      userName: payload.user ? payload.user.name : 'unknown',
      // All lead data from metadata
      leadEmail: meta.leadEmail || '',
      contactId: meta.contactId || '',
      leadId: meta.leadId || '',
      teamId: meta.teamId || '',
      sendUserId: meta.sendUserId || '',
      senderEmail: meta.senderEmail || '',
      sendUserMailboxId: meta.sendUserMailboxId || '',
      subject: meta.subject || '',
      category: meta.category || '',
      draft: editedDraft
    }
  }];
}

// Block actions (button clicks)
const action = payload.actions && payload.actions[0];
const actionId = action ? action.action_id : 'unknown';
const actionValue = action && action.value ? JSON.parse(action.value) : {};
const channel = payload.channel ? payload.channel.id : '';
const messageTs = payload.message ? payload.message.ts : '';
const originalBlocks = payload.message ? payload.message.blocks : [];
const userName = payload.user ? payload.user.name : 'unknown';
const triggerId = payload.trigger_id || null;

let actionType = 'decline';
if (actionId === 'lemlist_approve') actionType = 'approve';
else if (actionId === 'lemlist_edit') actionType = 'edit';
else if (actionId === 'lemlist_disapprove') actionType = 'decline';

return [{
  json: {
    actionType,
    triggerId,
    channel,
    messageTs,
    originalBlocks,
    userName,
    editedDraft: null,
    ...actionValue
  }
}];

