// Webhook trigger: unwrap body and pass through
// Each webhook event = one reply, no deduplication needed
const item = $input.first().json;
const body = item.body || item;

// Pass the body fields directly so downstream nodes
// can access them via $json.fieldName (not $json.body.fieldName)
return [{ json: body }];

function extractCleanReply(html, fallbackText = "") {
  if (!html) return fallbackText || "";

  // 1. Remove problematic blocks (Outlook, Gmail, etc.)
  html = html
    .replace(/<style[\s\S]*?>[\s\S]*?<\/style>/gi, "")
    .replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, "")
    .replace(/<!--[\s\S]*?-->/g, "");

  // 2. Normalize line breaks
  html = html.replace(/<br\s*\/?>/gi, "\n");

  // 3. Cut HTML reply blocks (first match only)
  const splitPatterns = [
    'class="gmail_quote',
    'gmail_quote_container',
    '<blockquote',
    'class="WordSection',
    'id="replySplit"',
    'class="OutlookMessageHeader'
  ];

  for (const pattern of splitPatterns) {
    const index = html.toLowerCase().indexOf(pattern.toLowerCase());
    if (index !== -1) {
      let tagStart = index;
      while (tagStart > 0 && html[tagStart] !== '<') {
        tagStart--;
      }
      html = html.substring(0, tagStart > 0 ? tagStart : index);
      break;
    }
  }

  // 4. Convert HTML → text
  let text = html
    .replace(/<\/div>/gi, "\n")
    .replace(/<\/p>/gi, "\n")
    .replace(/<[^>]*>/g, "")
    .replace(/&nbsp;/gi, " ")
    .replace(/&#39;/g, "'")
    .replace(/&amp;/g, "&")
    .replace(/&quot;/g, '"')
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">");

  // 5. Normalize whitespace (CRITICAL)
  text = text
    .replace(/\u00A0/g, " ")
    .replace(/\r/g, "")
    .replace(/[ \t]+/g, " ")
    .replace(/\n{2,}/g, "\n")
    .trim();

  // 6. Detect reply boundaries (multilingual + flexible)
  const replySeparators = [
    /^on .+wrote:$/i,
    /^le .+a écrit\s*:?\s*$/i,

    /^(from|de)\s*:\s*/i,
    /^(sent|envoyé)\s*:\s*/i,
    /^(to|à)\s*:\s*/i,
    /^(subject|objet)\s*:\s*/i,

    /^---+/,
  ];

  const lines = text.split("\n");
  let cleanLines = [];

  for (let line of lines) {
    const normalized = line
      .replace(/\u00A0/g, " ")
      .trim();

    const isReply = replySeparators.some((regex) =>
      regex.test(normalized)
    );

    const looksLikeEmailHeader =
      normalized.includes("@") &&
      (normalized.toLowerCase().includes("de") ||
       normalized.toLowerCase().includes("from"));

    if (isReply || looksLikeEmailHeader) break;

    cleanLines.push(line);
  }

  text = cleanLines.join("\n").trim();

  // 7. Remove common signatures
  const signaturePatterns = [
    /^--\s*$/,
    /^best regards[, ]*$/i,
    /^kind regards[, ]*$/i,
    /^cordialement[, ]*$/i,
    /^bien cordialement[, ]*$/i,
    /^sent from my/i
  ];

  const finalLines = text.split("\n");
  let result = [];

  for (let line of finalLines) {
    const trimmed = line.trim();

    const isSignature = signaturePatterns.some((regex) =>
      regex.test(trimmed)
    );

    if (isSignature) break;

    result.push(line);
  }

  text = result.join("\n").trim();

  // 8. Fix escaped newlines (🔥 your issue)
  text = text.replace(/\\n/g, "\n");

  // Optional: collapse multiple line breaks nicely
  text = text.replace(/\n{2,}/g, "\n");

  // 9. Fallback if result is too small
  if (!text || text.length < 10) {
    return fallbackText || "";
  }

  return text;
}


// n8n loop
for (const item of $input.all()) {
  const html =
    item.json.body?.html ||
    item.json.html ||
    "";

  const text =
    item.json.body?.text ||
    item.json.body?.messagePreview ||
    item.json.text ||
    item.json.messagePreview ||
    "";

  const cleaned = extractCleanReply(html, text);

  item.json.cleanedReply = cleaned;
}

return $input.all();
